import xml.etree.ElementTree as ET

def validate_xml(xml_string):
    try:
        root = ET.fromstring(xml_string)
        if not root.tag.endswith('}'):
            raise ET.ParseError("Invalid XML")
        return True, root
    except ET.ParseError as e:
        return False, str(e)

# Example usage
xml_string = """
<root>
  <person>
    <name>John</name>
    <age>30</age>
  </person>
</root>
"""

is_valid, error_message = validate_xml(xml_string)
if is_valid:
    print("XML is valid")
else:
    print(error_message)